1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - base premiums", () => {
6	    it("should return 5 G for empty item list (processing fee only)", () => {
7	      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
8	    });
9	    it("should return 105 G for a plain sword (100 base + 5 fee)", () => {
10	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }])).toBe(105);
11	    });
12	    it("should return 65 G for a plain amulet (60 base + 5 fee)", () => {
13	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }])).toBe(65);
14	    });
15	    it("should return 85 G for a plain staff (80 base + 5 fee)", () => {
16	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }])).toBe(85);
17	    });
18	    it("should return 45 G for a plain potion (40 base + 5 fee)", () => {
19	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }])).toBe(45);
20	    });
21	    it("should return 30 G for a single rune (25 base + 5 fee)", () => {
22	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }])).toBe(30);
23	    });
24	    it("should return 30 G for a single moonstone (25 base + 5 fee)", () => {
25	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "moonstone" }])).toBe(30);
26	    });
27	  });
28	
29	  describe("quote - multiple items", () => {
30	    it("should sum base premiums for two different main items (sword + amulet = 165 G)", () => {
31	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }, { type: "amulet" }])).toBe(165);
32	    });
33	    it("should return 55 G for two runes (50 base + 5 fee)", () => {
34	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }])).toBe(55);
35	    });
36	  });
37	
38	  describe("quote - component blocks", () => {
39	    it("should apply block premium of 60 G for exactly 3 alike runes (65 G total)", () => {
40	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(65);
41	    });
42	    it("should apply block premium of 60 G for exactly 3 alike moonstones (65 G total)", () => {
43	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }])).toBe(65);
44	    });
45	    it("should not apply block for 4 runes — charge 100 G base (105 G total)", () => {
46	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(105);
47	    });
48	    it("should apply one block + singles for 7 runes — 175 G base (180 G total)", () => {
49	      expect(
50	        quote({ yearsWithMHPCO: 0 }, [
51	          { type: "rune" },
52	          { type: "rune" },
53	          { type: "rune" },
54	          { type: "rune" },
55	          { type: "rune" },
56	          { type: "rune" },
57	          { type: "rune" },
58	        ]),
59	      ).toBe(180);
60	    });
61	    it("should apply two separate blocks for 3 runes + 3 moonstones — 120 G base (125 G total)", () => {
62	      expect(
63	        quote({ yearsWithMHPCO: 0 }, [
64	          { type: "rune" },
65	          { type: "rune" },
66	          { type: "rune" },
67	          { type: "moonstone" },
68	          { type: "moonstone" },
69	          { type: "moonstone" },
70	        ]),
71	      ).toBe(125);
72	    });
73	    it("should not apply block for 2 runes + 1 moonstone — 75 G base (80 G total)", () => {
74	      expect(
75	        quote({ yearsWithMHPCO: 0 }, [
76	          { type: "rune" },
77	          { type: "rune" },
78	          { type: "moonstone" },
79	        ]),
80	      ).toBe(80);
81	    });
82	  });
83	
84	  describe("quote - item-specific modifiers", () => {
85	    it("should add 50% curse surcharge to a cursed sword (100 + 50 + 5 = 155 G)", () => {
86	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }])).toBe(155);
87	    });
88	    it("should add 30% high-enchantment surcharge to a sword with enchantment 5 (100 + 30 + 5 = 135 G)", () => {
89	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 5 }])).toBe(135);
90	    });
91	    it("should not add high-enchantment surcharge to a sword with enchantment 4 (100 + 5 = 105 G)", () => {
92	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 4 }])).toBe(105);
93	    });
94	    it("should add both curse and high-enchantment surcharges when both apply (100 + 50 + 30 + 5 = 185 G)", () => {
95	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true, enchantment: 5 }])).toBe(185);
96	    });
97	    it("should apply curse surcharge only to the cursed item in a multi-item policy (cursed sword + plain amulet = 100+60+50+5 = 215 G)", () => {
98	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }])).toBe(215);
99	    });
100	  });
101	
102	  describe("quote - policy-wide modifiers", () => {
103	    it("should apply 20% loyalty discount for customer with 2 years (100 - 20 + 5 = 85 G)", () => {
104	      expect(quote({ yearsWithMHPCO: 2 }, [{ type: "sword" }])).toBe(85);
105	    });
106	    it("should apply 20% loyalty discount for customer with 3 years", () => {
107	      expect(quote({ yearsWithMHPCO: 3 }, [{ type: "sword" }])).toBe(85);
108	    });
109	    it("should not apply loyalty discount for customer with 1 year (100 + 5 = 105 G)", () => {
110	      expect(quote({ yearsWithMHPCO: 1 }, [{ type: "sword" }])).toBe(105);
111	    });
112	    it.todo("should apply 10% first insurance surcharge per item in a quote (100 + 10 + 5 = 115 G for one sword)");
113	    it.todo("should apply 15% follow-up discount on the customer's second quote (100 - 15 + 5 = 90 G base/loyalty-free)");
114	    it.todo("should not apply follow-up discount on the first quote");
115	  });
116	
117	  describe("quote - rounding and fee", () => {
118	    it.todo("should round final premium UP to whole G (197.5 -> 198 G)");
119	    it.todo("should add 5 G processing fee at the very end");
120	  });
121	
122	  describe("quote - integration examples", () => {
123	    it.todo("should compute 165 G for newcomer with cursed sword (steel, enchantment 3), first quote");
124	    it.todo("should compute 160 G for long-standing customer's second quote of cursed sword (steel, enchantment 7)");
125	  });
126	
127	  describe("quote - error cases", () => {
128	    it.todo("should throw an error for unknown item type in quote");
129	  });
130	
131	  describe("claim - base reimbursement", () => {
132	    it.todo("should pay out 400 G for regular sword (steel, enchantment 3) with 500 G damage (500 - 100 deductible)");
133	    it.todo("should pay out 100 G for a rune with 200 G damage (200 - 100 deductible)");
134	    it.todo("should apply 100 G deductible per damaged item (sword 500 + amulet 300 = 600 G payout)");
135	  });
136	
137	  describe("claim - special clauses", () => {
138	    it.todo("should reimburse 50% for items with enchantment >= 8 (steel sword ench 9, damage 1000 -> 400 G)");
139	    it.todo("should reimburse 50% for items with enchantment exactly 8 (dragon sword ench 8, damage 1000 -> 400 G)");
140	    it.todo("should fully reimburse dragon material items (dragon sword ench 5, damage 800 -> 700 G)");
141	    it.todo("should apply 50% rule when both high-enchantment and dragon material apply (dragon sword ench 9, damage 1000 -> 400 G)");
142	  });
143	
144	  describe("claim - rounding", () => {
145	    it.todo("should round final payout DOWN to whole G (350.5 -> 350 G)");
146	  });
147	
148	  describe("claim - error cases", () => {
149	    it.todo("should throw an error when claim references an item type not in the policy");
150	    it.todo("should throw an error when claim damage amount is negative");
151	    it.todo("should throw an error when claim has more damage entries of a type than the policy covers");
152	  });
153	});
